import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { LayoutDashboard, PlusCircle, List, Home, CreditCard, Wallet } from 'lucide-react';

const Sidebar = () => {
  const location = useLocation();

  // Função para verificar se a rota está ativa
  const isActive = (path) => location.pathname === path;

  return (
    <>
      <style>{`
        /* --- ESTILO DESKTOP (SIDEBAR) --- */
        .sidebar-container {
          width: 260px;
          height: 100vh;
          background: #ffffff;
          border-right: 1px solid #f1f5f9;
          padding: 30px 20px;
          position: fixed;
          left: 0;
          top: 0;
          display: flex;
          flex-direction: column;
          z-index: 1000;
          transition: all 0.3s ease;
        }

        .logo {
          display: flex;
          align-items: center;
          gap: 12px;
          font-size: 1.4rem;
          font-weight: 800;
          color: #4361ee;
          margin-bottom: 40px;
          padding-left: 10px;
        }

        .nav-list {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .nav-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 14px 18px;
          text-decoration: none;
          color: #64748b;
          font-weight: 600;
          border-radius: 14px;
          transition: all 0.2s ease;
        }

        .nav-item:hover {
          background: #f8fafc;
          color: #4361ee;
        }

        .nav-item.active {
          background: #4361ee15;
          color: #4361ee;
        }

        /* --- ESTILO MOBILE (BOTTOM BAR) --- */
        @media (max-width: 768px) {
          .sidebar-container {
            width: 100%;
            height: 70px;
            bottom: 0;
            top: auto;
            flex-direction: row;
            padding: 0 10px;
            border-right: none;
            border-top: 1px solid #f1f5f9;
            justify-content: space-around;
            align-items: center;
            box-shadow: 0 -4px 15px rgba(0,0,0,0.05);
          }

          .logo {
            display: none; /* Esconde o logo no mobile para ganhar espaço */
          }

          .nav-list {
            flex-direction: row;
            width: 100%;
            justify-content: space-around;
            gap: 0;
          }

          .nav-item {
            flex-direction: column;
            gap: 4px;
            padding: 8px;
            font-size: 0.65rem;
            border-radius: 10px;
            flex: 1;
            text-align: center;
          }

          .nav-item svg {
            width: 22px;
            height: 22px;
          }
          
          /* Ajuste para o conteúdo da página não ficar embaixo da barra no mobile */
          body {
            padding-bottom: 70px;
            padding-left: 0 !important;
          }
        }

        /* Ajuste de padding para desktop */
        @media (min-width: 769px) {
          body {
            padding-left: 260px;
          }
        }
      `}</style>

      <aside className="sidebar-container">
        <div className="logo">
          <Wallet size={28} fill="#4361ee30" />
          <span>Finanças</span>
        </div>

        <nav className="nav-list">
          <Link to="/" className={`nav-item ${isActive('/') ? 'active' : ''}`}>
            <Home />
            <span>Início</span>
          </Link>

          <Link to="/lancamento" className={`nav-item ${isActive('/lancamento') ? 'active' : ''}`}>
            <PlusCircle />
            <span>Novo</span>
          </Link>

          <Link to="/listagem" className={`nav-item ${isActive('/listagem') ? 'active' : ''}`}>
            <List />
            <span>Extrato</span>
          </Link>

          <Link to="/cartoes" className={`nav-item ${isActive('/cartoes') ? 'active' : ''}`}>
            <CreditCard />
            <span>Cartões</span>
          </Link>

          <Link to="/dashboard" className={`nav-item ${isActive('/dashboard') ? 'active' : ''}`}>
            <LayoutDashboard />
            <span>Painel</span>
          </Link>
        </nav>
      </aside>
    </>
  );
};

export default Sidebar;
